window.QUIZ_REGISTRY = window.QUIZ_REGISTRY || [];
window.QUIZ_REGISTRY.push({
  id: "7-martis-testi",
  title: "7 მარტის ტესტი",
  questions: [
  { id:1, text:"ჩამოთვლილთაგან, რომელი მიეკუთვნება ნივთიერებას?", options:["ავტომობილი","ალუმინის კოვზი","ოქრო","ბეჭედი","წყლის წვეთი"], answer:2, explanation:"\n    <b>ნივთიერება vs სხეული (საგანი)</b> — ფიზიკაში ეს ორი ცნება ერთმანეთისგან განსხვავდება:\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 400 120\" style=\"max-width:400px\">\n      <rect x=\"5\" y=\"5\" width=\"190\" height=\"110\" rx=\"8\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1.5\"/>\n      <text x=\"100\" y=\"28\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"12\" font-weight=\"bold\">ნივთიერება (მასალა)</text>\n      <text x=\"100\" y=\"50\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"11\">ოქრო</text>\n      <text x=\"100\" y=\"68\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"11\">ალუმინი</text>\n      <text x=\"100\" y=\"86\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"11\">წყალი, რკინა...</text>\n      <text x=\"100\" y=\"106\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">რისგანაც კეთდება საგნები</text>\n      <rect x=\"205\" y=\"5\" width=\"190\" height=\"110\" rx=\"8\" fill=\"#1a2744\" stroke=\"#ff5c6c\" stroke-width=\"1.5\"/>\n      <text x=\"300\" y=\"28\" text-anchor=\"middle\" fill=\"#ff5c6c\" font-size=\"12\" font-weight=\"bold\">სხეული (საგანი)</text>\n      <text x=\"300\" y=\"50\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"11\">ავტომობილი</text>\n      <text x=\"300\" y=\"68\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"11\">კოვზი, ბეჭედი</text>\n      <text x=\"300\" y=\"86\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"11\">წყლის წვეთი</text>\n      <text x=\"300\" y=\"106\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">კონკრეტული ობიექტი</text>\n    </svg>\n    <br>\n    ავტომობილი, კოვზი, ბეჭედი, წვეთი — კონკრეტული საგნებია. <b>ოქრო</b> კი თავისთავად ნივთიერებაა (ქიმიური ელემენტი Au), რისგანაც შეიძლება ბეჭდის, ყელსაბამის და სხვა საგნების დამზადება.\n  " },

  { id:2, text:"წიგნი რომ გადავნომროთ, საჭიროა 210 ცალი ციფრის გამოყენება. რამდენ გვერდიანია წიგნი?", options:["106","100","102","90","96"], answer:0, explanation:"\n    <b>ციფრების დათვლა ეტაპობრივად:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 380 145\" style=\"max-width:380px\">\n      <rect x=\"5\" y=\"5\" width=\"370\" height=\"38\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"15\" y=\"28\" fill=\"#4f8cff\" font-size=\"11\" font-weight=\"bold\">ეტაპი 1:</text>\n      <text x=\"80\" y=\"28\" fill=\"#e4e7ef\" font-size=\"11\">გვ. 1–9 → 9 რიცხვი × 1 ციფრი = 9 ციფრი</text>\n      <rect x=\"5\" y=\"48\" width=\"370\" height=\"38\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"15\" y=\"71\" fill=\"#4f8cff\" font-size=\"11\" font-weight=\"bold\">ეტაპი 2:</text>\n      <text x=\"80\" y=\"71\" fill=\"#e4e7ef\" font-size=\"11\">გვ. 10–99 → 90 რიცხვი × 2 ციფრი = 180 ციფრი</text>\n      <rect x=\"5\" y=\"91\" width=\"370\" height=\"48\" rx=\"6\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1.5\"/>\n      <text x=\"15\" y=\"110\" fill=\"#2dd4a0\" font-size=\"11\" font-weight=\"bold\">ეტაპი 3:</text>\n      <text x=\"80\" y=\"110\" fill=\"#e4e7ef\" font-size=\"11\">დარჩა: 210 − 9 − 180 = 21 ციფრი</text>\n      <text x=\"80\" y=\"128\" fill=\"#e4e7ef\" font-size=\"11\">21 ÷ 3 = 7 სამნიშნა რიცხვი (100–106)</text>\n    </svg>\n    <br>\n    ერთნიშნა რიცხვებისთვის (1–9) საჭიროა 9 ციფრი. ორნიშნა რიცხვებისთვის (10–99) საჭიროა 180 ციფრი. ჯამში 189. დარჩენილი 21 ციფრი სამნიშნა რიცხვებზე მოდის: 21÷3 = 7 გვერდი (100, 101, 102, 103, 104, 105, <b>106</b>).\n  " },

  { id:3, text:"ჩამოთვლილთაგან, რომელია ნივთიერებათა ნარევი?", options:["წყალი","ჰაერი","ალუმინი","ჟანგბადი","სპილენძი"], answer:1, explanation:"\n    <b>ნარევი vs სუფთა ნივთიერება:</b>\n    <br><br>\n    <b>ნარევი</b> — შედგება ორი ან მეტი სხვადასხვა ნივთიერებისგან, რომლებიც ფიზიკურად არიან შერეული.\n    <br><b>სუფთა ნივთიერება</b> — შედგება მხოლოდ ერთი ტიპის ატომებისგან ან მოლეკულებისგან.\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 360 90\" style=\"max-width:360px\">\n      <rect x=\"5\" y=\"5\" width=\"170\" height=\"80\" rx=\"8\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1.5\"/>\n      <text x=\"90\" y=\"25\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"11\" font-weight=\"bold\">ჰაერი = ნარევი</text>\n      <text x=\"90\" y=\"44\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"10\">აზოტი N₂ ≈ 78%</text>\n      <text x=\"90\" y=\"58\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"10\">ჟანგბადი O₂ ≈ 21%</text>\n      <text x=\"90\" y=\"72\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"10\">CO₂, არგონი, ორთქლი...</text>\n      <rect x=\"185\" y=\"5\" width=\"170\" height=\"80\" rx=\"8\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"270\" y=\"25\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"11\" font-weight=\"bold\">სუფთა ნივთიერებები</text>\n      <text x=\"270\" y=\"46\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"10\">წყალი (H₂O)</text>\n      <text x=\"270\" y=\"60\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"10\">ალუმინი (Al)</text>\n      <text x=\"270\" y=\"74\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"10\">ჟანგბადი (O₂), სპილენძი (Cu)</text>\n    </svg>\n    <br>\n    <b>ჰაერი</b> შეიცავს აზოტს, ჟანგბადს, ნახშირორჟანგს, არგონს, წყლის ორთქლს და სხვა აირებს — ამიტომ ის <b>ნარევია</b>. დანარჩენი ვარიანტები (წყალი, ალუმინი, ჟანგბადი, სპილენძი) სუფთა ინდივიდუალური ნივთიერებებია.\n  " },

  { id:4, text:"დაფაზე ოთხი რიცხვია ამოწერილი. მათგან ყოველი შესაძლო სამეული შეკრიბეს და მიიღეს ჯამები: 27, 35, 37, 39. იპოვეთ ოთხივე რიცხვის ჯამი.", options:["40","43","46","50","არცერთი ზემოთჩამოთვლილი პასუხი სწორი არ არის"], answer:2, explanation:"\n    <b>ამოხსნის ლოგიკა:</b>\n    <br><br>\n    ვთქვათ ოთხი რიცხვია: a, b, c, d. ოთხიდან სამეულების ამოღება შეიძლება <b>4 გზით</b>:\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 340 130\" style=\"max-width:340px\">\n      <text x=\"10\" y=\"20\" fill=\"#4f8cff\" font-size=\"11\">a + b + c = 27</text>\n      <text x=\"10\" y=\"40\" fill=\"#4f8cff\" font-size=\"11\">a + b + d = 35</text>\n      <text x=\"10\" y=\"60\" fill=\"#4f8cff\" font-size=\"11\">a + c + d = 37</text>\n      <text x=\"10\" y=\"80\" fill=\"#4f8cff\" font-size=\"11\">b + c + d = 39</text>\n      <line x1=\"150\" y1=\"5\" x2=\"150\" y2=\"90\" stroke=\"#282d3e\" stroke-width=\"1\"/>\n      <text x=\"160\" y=\"20\" fill=\"#e4e7ef\" font-size=\"11\">თითოეული რიცხვი 3 სამეულში</text>\n      <text x=\"160\" y=\"40\" fill=\"#e4e7ef\" font-size=\"11\">შედის (ერთხელ გამოტოვებული).</text>\n      <text x=\"160\" y=\"65\" fill=\"#e4e7ef\" font-size=\"11\">ჯამების ჯამი =</text>\n      <text x=\"160\" y=\"85\" fill=\"#2dd4a0\" font-size=\"11\" font-weight=\"bold\">3 × (a+b+c+d)</text>\n      <rect x=\"5\" y=\"98\" width=\"330\" height=\"28\" rx=\"6\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1\"/>\n      <text x=\"170\" y=\"116\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"12\" font-weight=\"bold\">27+35+37+39 = 138 → 138 ÷ 3 = 46</text>\n    </svg>\n    <br>\n    ყოველ სამეულში ერთი რიცხვი გამოტოვებულია, ამიტომ ოთხივე ჯამს რომ შევკრიბავთ, თითოეული რიცხვი ზუსტად <b>3-ჯერ</b> დაითვლება. შესაბამისად: (a+b+c+d) = 138 ÷ 3 = <b>46</b>.\n  " },

  { id:5, text:"სურათზე მითითებულის გარდა, კიდევ რა არის საჭირო ნათურას ასანთებად?", options:["კიდევ ერთი ნათურა","მხოლოდ ჩამრთველ-ამომრთველი","მხოლოდ სადენი","ზამბარა","დენის წყარო (ელემენტი)"], answer:4, image:"images/q5.jpg", explanation:"\n    <b>ელექტრული წრედის 3 აუცილებელი კომპონენტი:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 320 100\" style=\"max-width:320px\">\n      <rect x=\"5\" y=\"5\" width=\"95\" height=\"90\" rx=\"8\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1.5\"/>\n      <text x=\"52\" y=\"30\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"10\" font-weight=\"bold\">1. ნათურა</text>\n      <text x=\"52\" y=\"50\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"18\">💡</text>\n      <text x=\"52\" y=\"72\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">აქვს ✓</text>\n      <rect x=\"112\" y=\"5\" width=\"95\" height=\"90\" rx=\"8\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1.5\"/>\n      <text x=\"160\" y=\"30\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"10\" font-weight=\"bold\">2. სადენი</text>\n      <text x=\"160\" y=\"50\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"18\">〰️</text>\n      <text x=\"160\" y=\"72\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">აქვს ✓</text>\n      <rect x=\"219\" y=\"5\" width=\"95\" height=\"90\" rx=\"8\" fill=\"#2a1a1a\" stroke=\"#ff5c6c\" stroke-width=\"2\"/>\n      <text x=\"267\" y=\"30\" text-anchor=\"middle\" fill=\"#ff5c6c\" font-size=\"10\" font-weight=\"bold\">3. დენის წყარო</text>\n      <text x=\"267\" y=\"50\" text-anchor=\"middle\" fill=\"#ff5c6c\" font-size=\"18\">🔋</text>\n      <text x=\"267\" y=\"72\" text-anchor=\"middle\" fill=\"#ff5c6c\" font-size=\"9\" font-weight=\"bold\">აკლია ✗</text>\n    </svg>\n    <br>\n    სურათზე უკვე ვხედავთ <b>ნათურას</b> (მოხმარებელი) და <b>სადენს</b> (გამტარი). ელექტრულ წრედში დენის გასატარებლად აუცილებელია <b>დენის წყარო</b> — ბატარეა ან ელემენტი, რომელიც ქმნის ძაბვას და აამოძრავებს ელექტრონებს სადენში. მის გარეშე წრედი ღიაა და დენი არ გაივლის.\n  " },

  { id:6, text:"მყარი სხეულებისა და სითხეების საერთო თვისებაა:", options:["ფორმისა და მოცულობის ცვლილება","ფორმისა და მოცულობის შენარჩუნება","მხოლოდ მოცულობის შენარჩუნება","ფორმის ადვილად ცვლილება","ფორმის შენარჩუნება"], answer:2, explanation:"\n    <b>ნივთიერების სამი აგრეგატული მდგომარეობის შედარება:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 380 115\" style=\"max-width:380px\">\n      <rect x=\"5\" y=\"5\" width=\"120\" height=\"105\" rx=\"8\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1.5\"/>\n      <text x=\"65\" y=\"25\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"11\" font-weight=\"bold\">🧊 მყარი</text>\n      <text x=\"65\" y=\"48\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"10\">ფორმა: ✓ ინარჩუნებს</text>\n      <text x=\"65\" y=\"66\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"10\">მოცულობა: ✓</text>\n      <text x=\"65\" y=\"98\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">მოლეკულები მჭიდროდ</text>\n      <rect x=\"133\" y=\"5\" width=\"120\" height=\"105\" rx=\"8\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1.5\"/>\n      <text x=\"193\" y=\"25\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"11\" font-weight=\"bold\">💧 სითხე</text>\n      <text x=\"193\" y=\"48\" text-anchor=\"middle\" fill=\"#ff5c6c\" font-size=\"10\">ფორმა: ✗ იცვლება</text>\n      <text x=\"193\" y=\"66\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"10\">მოცულობა: ✓</text>\n      <text x=\"193\" y=\"98\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">იღებს ჭურჭლის ფორმას</text>\n      <rect x=\"261\" y=\"5\" width=\"114\" height=\"105\" rx=\"8\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1.5\"/>\n      <text x=\"318\" y=\"25\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"11\" font-weight=\"bold\">💨 აირი</text>\n      <text x=\"318\" y=\"48\" text-anchor=\"middle\" fill=\"#ff5c6c\" font-size=\"10\">ფორმა: ✗</text>\n      <text x=\"318\" y=\"66\" text-anchor=\"middle\" fill=\"#ff5c6c\" font-size=\"10\">მოცულობა: ✗</text>\n      <text x=\"318\" y=\"98\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">ავსებს მთელ ჭურჭელს</text>\n    </svg>\n    <br>\n    მყარი სხეული ინარჩუნებს <b>ორივეს</b> — ფორმასა და მოცულობას. სითხე ინარჩუნებს <b>მოცულობას</b>, მაგრამ იღებს ჭურჭლის ფორმას. აირს არც ერთი არ აქვს ფიქსირებული. ამიტომ მყარი სხეულისა და სითხის <b>საერთო</b> თვისება არის მხოლოდ <b>მოცულობის შენარჩუნება</b>.\n  " },

  { id:7, text:"10 პრინტერი იმდენი ღირს, რამდენიც 3 პროექტორი. 1 პროექტორი 3 პრინტერზე 170 ლარით ძვირია. რა ღირს პრინტერი?", options:["1700 ლ","510 ლ","690 ლ","1920 ლ","450 ლ"], answer:1, explanation:"\n    <b>ალგებრული ამოხსნა ნაბიჯ-ნაბიჯ:</b>\n    <br><br>\n    ვთქვათ პრინტერის ფასი = <b>P</b>, პროექტორის = <b>Q</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 360 130\" style=\"max-width:360px\">\n      <rect x=\"5\" y=\"5\" width=\"350\" height=\"30\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"15\" y=\"24\" fill=\"#4f8cff\" font-size=\"11\">პირობა 1: 10P = 3Q → Q = 10P/3</text>\n      <rect x=\"5\" y=\"40\" width=\"350\" height=\"30\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"15\" y=\"59\" fill=\"#4f8cff\" font-size=\"11\">პირობა 2: Q = 3P + 170</text>\n      <rect x=\"5\" y=\"78\" width=\"350\" height=\"45\" rx=\"6\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1.5\"/>\n      <text x=\"15\" y=\"96\" fill=\"#2dd4a0\" font-size=\"11\">ვტოლებთ: 10P/3 = 3P + 170</text>\n      <text x=\"15\" y=\"114\" fill=\"#2dd4a0\" font-size=\"11\" font-weight=\"bold\">10P = 9P + 510 → P = 510 ლარი</text>\n    </svg>\n    <br>\n    <b>შემოწმება:</b> პროექტორი = 10×510/3 = 1700 ლ. 3 პრინტერი = 1530 ლ. სხვაობა = 1700−1530 = 170 ✓\n  " },

  { id:8, text:"ოთახში თერმომეტრი 25 გრადუს ცელსიუსს აჩვენებს. ამ ოთახში არსებული ნივთების ჩამონათვალიდან, რომელი მასალით დამზადებული საგნის ტემპერატურა იქნება ყველაზე მაღალი?", options:["ლითონის","ხის","კერამიკის","პლასტმასის","ყველა სხეულის ტემპერატურა ერთნაირია"], answer:4, explanation:"\n    <b>თერმული წონასწორობის კანონი:</b>\n    <br><br>\n    როდესაც საგნები დიდი ხნით ერთ ოთახში იმყოფებიან, ისინი <b>თერმულ წონასწორობას</b> აღწევენ — ყველას ერთი და იგივე ტემპერატურა აქვს: <b>25°C</b>.\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 340 70\" style=\"max-width:340px\">\n      <rect x=\"5\" y=\"5\" width=\"78\" height=\"60\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"44\" y=\"25\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"10\">🔩 ლითონი</text>\n      <text x=\"44\" y=\"48\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"12\" font-weight=\"bold\">25°C</text>\n      <rect x=\"88\" y=\"5\" width=\"78\" height=\"60\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"127\" y=\"25\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"10\">🪵 ხე</text>\n      <text x=\"127\" y=\"48\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"12\" font-weight=\"bold\">25°C</text>\n      <rect x=\"171\" y=\"5\" width=\"78\" height=\"60\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"210\" y=\"25\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"10\">🏺 კერამიკა</text>\n      <text x=\"210\" y=\"48\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"12\" font-weight=\"bold\">25°C</text>\n      <rect x=\"254\" y=\"5\" width=\"78\" height=\"60\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"293\" y=\"25\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"10\">🧴 პლასტმასი</text>\n      <text x=\"293\" y=\"48\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"12\" font-weight=\"bold\">25°C</text>\n    </svg>\n    <br>\n    <b>მაშინ რატომ გვეჩვენება ლითონი ცივი?</b> ლითონს მაღალი სითბოგამტარობა აქვს — ის სწრაფად „წაართმევს\" სითბოს ხელს, ამიტომ ცივად აღვიქვამთ. მაგრამ ტემპერატურა <b>ყველას ერთნაირი</b> აქვს.\n  " },

  { id:9, text:"თუ 12 ნათურადან თითოეულს შევაერთებთ დანარჩენ ყველასთან თითო-თითო სადენით, სულ რამდენი სადენი დაგვჭირდება?", options:["66","72","78","24","48"], answer:0, explanation:"\n    <b>კომბინატორიკა — წყვილების დათვლა:</b>\n    <br><br>\n    ყოველი სადენი აკავშირებს ზუსტად 2 ნათურას. ანუ ვეძებთ: 12 ელემენტიდან რამდენი <b>უნიკალური წყვილი</b> შეიძლება?\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 340 85\" style=\"max-width:340px\">\n      <rect x=\"5\" y=\"5\" width=\"330\" height=\"75\" rx=\"8\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1.5\"/>\n      <text x=\"170\" y=\"28\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"12\" font-weight=\"bold\">C(n, 2) = n × (n−1) / 2</text>\n      <text x=\"170\" y=\"50\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"11\">C(12, 2) = 12 × 11 / 2</text>\n      <text x=\"170\" y=\"70\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"14\" font-weight=\"bold\">= 132 / 2 = 66 სადენი</text>\n    </svg>\n    <br>\n    <b>რატომ ვყოფთ 2-ზე?</b> 1-ლი ნათურა ერთდება 11 სხვასთან, მე-2 — 10 ახალთან (1-თან უკვე ჩაითვალა), მე-3 — 9-თან და ა.შ. ან: 12×11 = 132, მაგრამ ყოველი სადენი ორჯერ დაითვალა (A→B და B→A), ამიტომ 132÷2 = <b>66</b>.\n  " },

  { id:10, text:"გვაქვს ორი ერთნაირი ტოლგვერდა სამკუთხედი. თითოეულის პერიმეტრი 27 სმ-ია. რისი ტოლი იქნება იმ რომბის პერიმეტრი, რომელიც ამ სამკუთხედების ერთმანეთზე მიდგმით მიიღება?", options:["27 სმ","18 სმ","45 სმ","30 სმ","36 სმ"], answer:4, explanation:"\n    <b>ვიზუალური ამოხსნა:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 380 150\" style=\"max-width:380px\">\n      <!-- Left: two separate triangles -->\n      <polygon points=\"30,70 65,10 100,70\" fill=\"rgba(79,140,255,0.1)\" stroke=\"#4f8cff\" stroke-width=\"2\"/>\n      <text x=\"40\" y=\"48\" fill=\"#4f8cff\" font-size=\"9\">9</text>\n      <text x=\"88\" y=\"48\" fill=\"#4f8cff\" font-size=\"9\">9</text>\n      <text x=\"65\" y=\"67\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"9\">9</text>\n      <polygon points=\"30,70 65,130 100,70\" fill=\"rgba(255,92,108,0.1)\" stroke=\"#ff5c6c\" stroke-width=\"2\"/>\n      <text x=\"40\" y=\"100\" fill=\"#ff5c6c\" font-size=\"9\">9</text>\n      <text x=\"88\" y=\"100\" fill=\"#ff5c6c\" font-size=\"9\">9</text>\n      <text x=\"65\" y=\"78\" text-anchor=\"middle\" fill=\"#ff5c6c\" font-size=\"9\">9</text>\n      <text x=\"65\" y=\"140\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"8\">2 სამკუთხედი</text>\n      <!-- Arrow -->\n      <text x=\"130\" y=\"75\" fill=\"#7a7f95\" font-size=\"22\">→</text>\n      <!-- Right: rhombus (diamond) -->\n      <polygon points=\"260,10 330,70 260,130 190,70\" fill=\"rgba(45,212,160,0.08)\" stroke=\"#2dd4a0\" stroke-width=\"2.5\"/>\n      <line x1=\"190\" y1=\"70\" x2=\"330\" y2=\"70\" stroke=\"#7a7f95\" stroke-width=\"1\" stroke-dasharray=\"4\"/>\n      <text x=\"260\" y=\"67\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"8\">საერთო გვერდი</text>\n      <text x=\"218\" y=\"38\" fill=\"#2dd4a0\" font-size=\"10\" font-weight=\"bold\">9</text>\n      <text x=\"298\" y=\"38\" fill=\"#2dd4a0\" font-size=\"10\" font-weight=\"bold\">9</text>\n      <text x=\"218\" y=\"108\" fill=\"#2dd4a0\" font-size=\"10\" font-weight=\"bold\">9</text>\n      <text x=\"298\" y=\"108\" fill=\"#2dd4a0\" font-size=\"10\" font-weight=\"bold\">9</text>\n      <text x=\"260\" y=\"140\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"9\" font-weight=\"bold\">რომბი: P = 4 × 9 = 36</text>\n    </svg>\n    <br>\n    თითოეული გვერდი = 27 ÷ 3 = <b>9 სმ</b>. ორი სამკუთხედის ერთ გვერდზე შეწებებისას მიიღება რომბი. საერთო გვერდი „შიგნით\" ჩადის და პერიმეტრში არ ითვლება. რომბის 4 გვერდი × 9 = <b>36 სმ</b>.\n  " },

  { id:11, text:"ჩამოთვლილთაგან, რომელი აღწერს საუკეთესოდ იმას, თუ რა იცვლება როდესაც შოკოლადის ფილა დნება?", options:["სითხე ხდება აირადი","მყარი სხეული ხდება თხევადი","მყარი სხეული ხდება აირადი","სითხე ხდება მყარი სხეული","აირი ხდება სითხე"], answer:1, explanation:"\n    <b>აგრეგატული გარდაქმნები:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 350 60\" style=\"max-width:350px\">\n      <rect x=\"5\" y=\"10\" width=\"85\" height=\"40\" rx=\"8\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1.5\"/>\n      <text x=\"47\" y=\"35\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"11\" font-weight=\"bold\">🧊 მყარი</text>\n      <line x1=\"95\" y1=\"30\" x2=\"135\" y2=\"30\" stroke=\"#2dd4a0\" stroke-width=\"2\" marker-end=\"url(#arr)\"/>\n      <text x=\"115\" y=\"22\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"9\">დნობა</text>\n      <rect x=\"140\" y=\"10\" width=\"85\" height=\"40\" rx=\"8\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"2\"/>\n      <text x=\"182\" y=\"35\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"11\" font-weight=\"bold\">💧 თხევადი</text>\n      <line x1=\"230\" y1=\"30\" x2=\"270\" y2=\"30\" stroke=\"#7a7f95\" stroke-width=\"1.5\" marker-end=\"url(#arr2)\"/>\n      <text x=\"250\" y=\"22\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">ადუღება</text>\n      <rect x=\"275\" y=\"10\" width=\"70\" height=\"40\" rx=\"8\" fill=\"#1a2744\" stroke=\"#7a7f95\" stroke-width=\"1\"/>\n      <text x=\"310\" y=\"35\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"11\">💨 აირი</text>\n    </svg>\n    <br>\n    <b>დნობა</b> = მყარი → თხევადი. შოკოლადი ოთახის ტემპერატურაზე მყარია. როდესაც ის ხელში ან სითბოსთან ახლოს დნება, მყარი აგრეგატული მდგომარეობიდან <b>თხევადში</b> გადადის. არ ორთქლდება (არ ხდება აირადი), ამიტომ სწორი პასუხია <b>„მყარი სხეული ხდება თხევადი\"</b>.\n  " },

  { id:12, text:"ერთი მორის 5 ნაწილად დახერხვას სჭირდება 16 წამი. რა დრო დასჭირდება 1 მორის 10 ნაწილად დახერხვას?", options:["32 წამი","36 წამი","40 წამი","44 წამი","20 წამი"], answer:1, explanation:"\n    <b>მთავარი ხრიკი: ჭრების რაოდენობა ≠ ნაწილების რაოდენობა!</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 360 100\" style=\"max-width:360px\">\n      <rect x=\"10\" y=\"15\" width=\"200\" height=\"20\" rx=\"4\" fill=\"#4f8cff\" opacity=\"0.3\"/>\n      <line x1=\"60\" y1=\"10\" x2=\"60\" y2=\"40\" stroke=\"#ff5c6c\" stroke-width=\"2\"/>\n      <line x1=\"110\" y1=\"10\" x2=\"110\" y2=\"40\" stroke=\"#ff5c6c\" stroke-width=\"2\"/>\n      <line x1=\"160\" y1=\"10\" x2=\"160\" y2=\"40\" stroke=\"#ff5c6c\" stroke-width=\"2\"/>\n      <line x1=\"210\" y1=\"10\" x2=\"210\" y2=\"40\" stroke=\"#ff5c6c\" stroke-width=\"2\" stroke-dasharray=\"0\"/>\n      <text x=\"35\" y=\"55\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"9\">1</text>\n      <text x=\"85\" y=\"55\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"9\">2</text>\n      <text x=\"135\" y=\"55\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"9\">3</text>\n      <text x=\"185\" y=\"55\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"9\">4</text>\n      <text x=\"225\" y=\"55\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"9\">5</text>\n      <text x=\"240\" y=\"30\" fill=\"#ff5c6c\" font-size=\"10\">← 4 ჭრა</text>\n      <text x=\"110\" y=\"8\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">5 ნაწილი</text>\n      <rect x=\"10\" y=\"70\" width=\"340\" height=\"24\" rx=\"6\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1\"/>\n      <text x=\"180\" y=\"86\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"11\">5 ნაწილი → 4 ჭრა | 1 ჭრა = 16/4 = 4 წამი</text>\n    </svg>\n    <br>\n    N ნაწილად დასაჭრელად საჭიროა <b>(N−1) ჭრა</b>. 5 ნაწილი = 4 ჭრა. ერთი ჭრა = 16÷4 = <b>4 წამი</b>.\n    <br>10 ნაწილი = 9 ჭრა. 9 × 4 = <b>36 წამი</b>.\n    <br><br>\n    <b>ხშირი შეცდომა:</b> 16×2=32 (არასწორია, რადგან ჭრების რაოდენობა არ ორმაგდება).\n  " },

  { id:13, text:"რისი ტოლია სურათზე მოცემული ფიგურის პერიმეტრი?", options:["47 სმ","72 სმ","69 სმ","94 სმ","106 სმ"], answer:3, image:"images/q13.jpg", explanation:"\n    <b>პერიმეტრის გამოთვლა — ფიგურის ყველა გარე გვერდი:</b>\n    <br><br>\n    ეს ფიგურა არის დიდი მართკუთხედი, რომელსაც ზემოდან აქვს ამოჭრილი ნაწილი. მთავარი პრინციპი: <b>ამოჭრილ ფიგურაში ჰორიზონტალური მონაკვეთების ჯამი = ქვედა ფუძე, ვერტიკალური მონაკვეთების ჯამი = მარცხენა მხარე</b>.\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 340 70\" style=\"max-width:340px\">\n      <rect x=\"5\" y=\"5\" width=\"330\" height=\"55\" rx=\"6\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1\"/>\n      <text x=\"170\" y=\"25\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"11\">ყველა ჰორიზონტალური = 25 + 25 = 50 სმ</text>\n      <text x=\"170\" y=\"42\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"11\">ყველა ვერტიკალური = 12 + 10 + 12 + 10 = 44 სმ</text>\n      <text x=\"170\" y=\"56\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"11\" font-weight=\"bold\">P = 50 + 44 = 94 სმ</text>\n    </svg>\n    <br>\n    ჰორიზონტალური მონაკვეთები (ზედა და ქვედა) ჯამში = 25×2 = 50. ვერტიკალური მონაკვეთები (მარცხნივ 12 და მარჯვნივ 10, ორჯერ) = (12+10)×2 = 44. <b>პერიმეტრი = 94 სმ</b>.\n  " },

  { id:14, text:"რამდენ ათეულს მივიღებთ, თუ ცხრა ასეულს დავუმატებთ ხუთ ათეულს?", options:["14-ს","59-ს","95-ს","905-ს","950-ს"], answer:2, explanation:"\n    <b>თანრიგების გაგება:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 360 102\" style=\"max-width:360px\">\n      <rect x=\"5\" y=\"5\" width=\"170\" height=\"30\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"90\" y=\"24\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"11\">9 ასეული = 9 × 100 = 900</text>\n      <rect x=\"185\" y=\"5\" width=\"170\" height=\"30\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"270\" y=\"24\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"11\">5 ათეული = 5 × 10 = 50</text>\n      <rect x=\"5\" y=\"42\" width=\"350\" height=\"25\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"180\" y=\"58\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"11\">ჯამი: 900 + 50 = 950</text>\n      <rect x=\"5\" y=\"74\" width=\"350\" height=\"25\" rx=\"6\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1.5\"/>\n      <text x=\"180\" y=\"90\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"11\" font-weight=\"bold\">კითხვაა: 950-ში რამდენი ათეულია? → 950 ÷ 10 = 95</text>\n    </svg>\n    <br>\n    <b>ყურადღება:</b> კითხვა არ არის „რისი ტოლია?\", არამედ „რამდენ <b>ათეულს</b> მივიღებთ?\". 950 = <b>95 ათეული</b> (რადგან 95 × 10 = 950). პასუხი 950 არასწორი იქნებოდა, რადგან ის ტოლობაა, არა ათეულების რაოდენობა.\n  " },

  { id:15, text:"200 ადამიანიდან 90-ს მოსწონს ჩაის სმა, ხოლო 108-ს - ყავის. 46 ადამიანს მოსწონს ორივე. რამდენს არ მოსწონს ამ 200 ადამიანიდან არც ჩაის და არც ყავის სმა?", options:["48","46","44","42","40"], answer:0, explanation:"\n    <b>ვენის დიაგრამა და ინკლუზია-ექსკლუზიის პრინციპი:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 340 140\" style=\"max-width:340px\">\n      <circle cx=\"120\" cy=\"70\" r=\"55\" fill=\"rgba(79,140,255,0.15)\" stroke=\"#4f8cff\" stroke-width=\"1.5\"/>\n      <circle cx=\"210\" cy=\"70\" r=\"55\" fill=\"rgba(255,92,108,0.15)\" stroke=\"#ff5c6c\" stroke-width=\"1.5\"/>\n      <text x=\"85\" y=\"55\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"11\" font-weight=\"bold\">ჩაი</text>\n      <text x=\"85\" y=\"75\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"13\" font-weight=\"bold\">44</text>\n      <text x=\"85\" y=\"90\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">(90−46)</text>\n      <text x=\"165\" y=\"55\" text-anchor=\"middle\" fill=\"#a78bfa\" font-size=\"11\" font-weight=\"bold\">ორივე</text>\n      <text x=\"165\" y=\"75\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"13\" font-weight=\"bold\">46</text>\n      <text x=\"245\" y=\"55\" text-anchor=\"middle\" fill=\"#ff5c6c\" font-size=\"11\" font-weight=\"bold\">ყავა</text>\n      <text x=\"245\" y=\"75\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"13\" font-weight=\"bold\">62</text>\n      <text x=\"245\" y=\"90\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">(108−46)</text>\n      <text x=\"170\" y=\"130\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"10\">სულ: 44 + 46 + 62 = 152 → არცერთი: 200 − 152 = 48</text>\n    </svg>\n    <br>\n    <b>ფორმულა:</b> |ჩაი ∪ ყავა| = |ჩაი| + |ყავა| − |ორივე| = 90 + 108 − 46 = <b>152</b>\n    <br>\n    ერთი მაინც მოსწონს: 152 ადამიანს. არც ერთი: 200 − 152 = <b>48</b>.\n  " },

  { id:16, text:"ჩამოთვლილთაგან რისი ტოლია 3 ლიტრის 15%?", options:["150 მლ","300 მლ","450 მლ","600 მლ","900 მლ"], answer:2, explanation:"\n    <b>პროცენტის გამოთვლა:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 340 70\" style=\"max-width:340px\">\n      <rect x=\"5\" y=\"5\" width=\"330\" height=\"25\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"170\" y=\"22\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"11\">3 ლიტრი = 3000 მილილიტრი</text>\n      <rect x=\"5\" y=\"38\" width=\"330\" height=\"25\" rx=\"6\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1.5\"/>\n      <text x=\"170\" y=\"55\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"12\" font-weight=\"bold\">3000 × 15 ÷ 100 = 3000 × 0.15 = 450 მლ</text>\n    </svg>\n    <br>\n    ჯერ ლიტრები გადავიყვანოთ მილილიტრებში (1ლ = 1000მლ), შემდეგ 15%-ს ვითვლით: 3000 × 0.15 = <b>450 მლ</b>.\n  " },

  { id:17, text:"მასწავლებელს აქვს ოთხი სხვადასხვა წიგნი. რამდენი სხვადასხვა თანმიმდევრობით შეუძლია დაალაგოს ეს წიგნები ერთმანეთის მიყოლებით, თაროზე?", options:["6","12","24","16","20"], answer:2, explanation:"\n    <b>პერმუტაცია (ფაქტორიალი):</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 360 115\" style=\"max-width:360px\">\n      <text x=\"10\" y=\"20\" fill=\"#4f8cff\" font-size=\"11\">1-ლი ადგილი: 4 არჩევანი (ნებისმიერი წიგნი)</text>\n      <text x=\"10\" y=\"40\" fill=\"#4f8cff\" font-size=\"11\">მე-2 ადგილი: 3 არჩევანი (დარჩენილიდან)</text>\n      <text x=\"10\" y=\"60\" fill=\"#4f8cff\" font-size=\"11\">მე-3 ადგილი: 2 არჩევანი</text>\n      <text x=\"10\" y=\"80\" fill=\"#4f8cff\" font-size=\"11\">მე-4 ადგილი: 1 არჩევანი</text>\n      <rect x=\"5\" y=\"88\" width=\"350\" height=\"20\" rx=\"4\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1\"/>\n      <text x=\"180\" y=\"102\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"12\" font-weight=\"bold\">4! = 4 × 3 × 2 × 1 = 24</text>\n    </svg>\n    <br>\n    ყოველი მომდევნო ადგილისთვის ერთით ნაკლები არჩევანია, რადგან წინა წიგნი უკვე დალაგებულია. გამრავლების წესით: <b>4! = 24</b>.\n  " },

  { id:18, text:"საერთო ბიზნესიდან მიღებული ფული ანამ, ბაკურიმ, ციალამ და დათომ გაინაწილეს, შესაბამისად, 5:2:4:3 შეფარდებით. რა თანხა შეხვდა ანას, თუ ციალას შეხვდა 1000 ლარით მეტი ვიდრე ბაკურის?", options:["5000 ლარი","3500 ლარი","4000 ლარი","2000 ლარი","2500 ლარი"], answer:4, explanation:"\n    <b>პროპორციული განაწილება:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 360 110\" style=\"max-width:360px\">\n      <rect x=\"5\" y=\"5\" width=\"85\" height=\"40\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1.5\"/>\n      <text x=\"47\" y=\"22\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"10\" font-weight=\"bold\">ანა</text>\n      <text x=\"47\" y=\"38\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"12\">5x</text>\n      <rect x=\"95\" y=\"5\" width=\"85\" height=\"40\" rx=\"6\" fill=\"#1a2744\" stroke=\"#ff5c6c\" stroke-width=\"1.5\"/>\n      <text x=\"137\" y=\"22\" text-anchor=\"middle\" fill=\"#ff5c6c\" font-size=\"10\" font-weight=\"bold\">ბაკური</text>\n      <text x=\"137\" y=\"38\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"12\">2x</text>\n      <rect x=\"185\" y=\"5\" width=\"85\" height=\"40\" rx=\"6\" fill=\"#1a2744\" stroke=\"#2dd4a0\" stroke-width=\"1.5\"/>\n      <text x=\"227\" y=\"22\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"10\" font-weight=\"bold\">ციალა</text>\n      <text x=\"227\" y=\"38\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"12\">4x</text>\n      <rect x=\"275\" y=\"5\" width=\"80\" height=\"40\" rx=\"6\" fill=\"#1a2744\" stroke=\"#7a7f95\" stroke-width=\"1\"/>\n      <text x=\"315\" y=\"22\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"10\" font-weight=\"bold\">დათო</text>\n      <text x=\"315\" y=\"38\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"12\">3x</text>\n      <rect x=\"5\" y=\"55\" width=\"350\" height=\"50\" rx=\"6\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1\"/>\n      <text x=\"180\" y=\"73\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"11\">ციალა − ბაკური = 4x − 2x = 2x = 1000</text>\n      <text x=\"180\" y=\"93\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"12\" font-weight=\"bold\">x = 500 → ანა = 5 × 500 = 2500 ლარი</text>\n    </svg>\n    <br>\n    <b>შემოწმება:</b> ანა=2500, ბაკური=1000, ციალა=2000, დათო=1500. სხვაობა ციალა−ბაკური = 1000 ✓. შეფარდება: 2500:1000:2000:1500 = 5:2:4:3 ✓\n  " },

  { id:19, text:"გიორგის უნდა რომ იყიდოს სათამაშო რომელიც 96 ლარი ღირს. მას უკვე აქვს 24 ლარი და ყოველდღე აპირებს კიდევ 12 ლარის შეგროვებას. ჩამოთვლილთაგან რომელი განტოლებითაა შესაძლებელი ვიპოვოთ, რამდენ დღეში დააგროვებს გიორგი საკმარის თანხას?", options:["24x−12=96","12x−24=96","24x+12=96","12x+24=96","96x+24=12"], answer:3, explanation:"\n    <b>განტოლების შედგენა სიტყვიერი ამოცანიდან:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 370 80\" style=\"max-width:370px\">\n      <rect x=\"5\" y=\"5\" width=\"110\" height=\"35\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"60\" y=\"18\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">უკვე აქვს</text>\n      <text x=\"60\" y=\"33\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"12\" font-weight=\"bold\">24 ლარი</text>\n      <text x=\"123\" y=\"25\" fill=\"#e4e7ef\" font-size=\"14\">+</text>\n      <rect x=\"135\" y=\"5\" width=\"110\" height=\"35\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"190\" y=\"18\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">x დღეში დაგროვებს</text>\n      <text x=\"190\" y=\"33\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"12\" font-weight=\"bold\">12x ლარი</text>\n      <text x=\"253\" y=\"25\" fill=\"#e4e7ef\" font-size=\"14\">=</text>\n      <rect x=\"265\" y=\"5\" width=\"100\" height=\"35\" rx=\"6\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1.5\"/>\n      <text x=\"315\" y=\"18\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">საჭირო თანხა</text>\n      <text x=\"315\" y=\"33\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"12\" font-weight=\"bold\">96 ლარი</text>\n      <rect x=\"5\" y=\"50\" width=\"360\" height=\"25\" rx=\"6\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1\"/>\n      <text x=\"185\" y=\"66\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"12\" font-weight=\"bold\">24 + 12x = 96 → 12x + 24 = 96</text>\n    </svg>\n    <br>\n    <b>x</b> = დღეების რაოდენობა. 12x = ამდენი დღეში დაგროვებული. საწყისი 24 + დაგროვებული 12x = საჭირო 96. ამოხსნა: 12x = 72, <b>x = 6 დღე</b>.\n  " },

  { id:20, text:"ვიტრინაზე დევს 2 ერთმანეთისაგან განსხვავებული თეფში, 6 ერთმანეთისაგან განსხვავებული ფინჯანი და 7 ერთმანეთისაგან განსხვავებული კოვზი. რამდენნაირად შეიძლება შევარჩიოთ თეფში ფინჯნით და კოვზით?", options:["15","12","14","26","84"], answer:4, explanation:"\n    <b>გამრავლების წესი (კომბინატორიკა):</b>\n    <br><br>\n    თითოეული კატეგორიიდან 1-ს ვირჩევთ. არჩევანები <b>ერთმანეთისგან დამოუკიდებელია</b>.\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 340 60\" style=\"max-width:340px\">\n      <rect x=\"5\" y=\"5\" width=\"100\" height=\"45\" rx=\"8\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"55\" y=\"22\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"10\">🍽 თეფში</text>\n      <text x=\"55\" y=\"40\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"14\" font-weight=\"bold\">2</text>\n      <text x=\"113\" y=\"32\" fill=\"#e4e7ef\" font-size=\"16\">×</text>\n      <rect x=\"123\" y=\"5\" width=\"100\" height=\"45\" rx=\"8\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"173\" y=\"22\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"10\">☕ ფინჯანი</text>\n      <text x=\"173\" y=\"40\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"14\" font-weight=\"bold\">6</text>\n      <text x=\"231\" y=\"32\" fill=\"#e4e7ef\" font-size=\"16\">×</text>\n      <rect x=\"241\" y=\"5\" width=\"95\" height=\"45\" rx=\"8\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1.5\"/>\n      <text x=\"288\" y=\"22\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"10\">🥄 კოვზი</text>\n      <text x=\"288\" y=\"40\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"14\" font-weight=\"bold\">7</text>\n    </svg>\n    <br>\n    2 × 6 × 7 = <b>84</b> სხვადასხვა კომბინაცია. ანუ ყოველი თეფშისთვის 6 ფინჯანი, ყოველი წყვილისთვის 7 კოვზი.\n  " },

  { id:21, text:"გამოხდილი წყლის მისაღებად მას ჯერ ადუღებენ (ამ დროს ხდება ორთქლის კვლავ სითხედ გადაქცევა). გამოხდილ წყალს, სასმელ წყალთან შედარებით არ აქვს გემო. ქვემოთ ჩამოთვლილთაგან რომელი მიზეზი იწვევს განსხვავებას?", options:["წყალი დუღდება 100°C-ზე","წყალი ფართოვდება გაცხელებისას","ტემპერატურა არ ცვლის წყლის მასას","მინერალები ადუღებისას არ ორთქლდება","არცერთი პასუხი არ არის სწორი"], answer:3, explanation:"\n    <b>დისტილაციის (გამოხდის) პროცესი:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 370 70\" style=\"max-width:370px\">\n      <rect x=\"5\" y=\"5\" width=\"100\" height=\"55\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"55\" y=\"22\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"10\">💧 სასმელი წყალი</text>\n      <text x=\"55\" y=\"38\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"9\">H₂O + მინერალები</text>\n      <text x=\"55\" y=\"52\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">(Ca, Mg, Na...)</text>\n      <text x=\"115\" y=\"35\" fill=\"#e4e7ef\" font-size=\"12\">→ 🔥 →</text>\n      <rect x=\"150\" y=\"5\" width=\"90\" height=\"55\" rx=\"6\" fill=\"#1a2744\" stroke=\"#ff5c6c\" stroke-width=\"1\"/>\n      <text x=\"195\" y=\"22\" text-anchor=\"middle\" fill=\"#ff5c6c\" font-size=\"10\">💨 ორთქლი</text>\n      <text x=\"195\" y=\"38\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"9\">მხოლოდ H₂O</text>\n      <text x=\"195\" y=\"52\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">მინერალები რჩება!</text>\n      <text x=\"250\" y=\"35\" fill=\"#e4e7ef\" font-size=\"12\">→ ❄️ →</text>\n      <rect x=\"280\" y=\"5\" width=\"85\" height=\"55\" rx=\"6\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1.5\"/>\n      <text x=\"322\" y=\"22\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"10\">💧 გამოხდილი</text>\n      <text x=\"322\" y=\"38\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"9\">სუფთა H₂O</text>\n      <text x=\"322\" y=\"52\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"9\">უგემოვნო</text>\n    </svg>\n    <br>\n    სასმელი წყალი შეიცავს გახსნილ <b>მინერალურ მარილებს</b> (კალციუმი, მაგნიუმი, ნატრიუმი), რომლებიც მას გემოს აძლევს. ადუღებისას <b>წყალი ორთქლდება, მაგრამ მინერალები რჩება</b> ჭურჭელში — ვერ ორთქლდება. ორთქლის კონდენსაციით მიღებული წყალი „სუფთაა\" და უგემოვნო.\n  " },

  { id:22, text:"მზიან ამინდში ხის ჩრდილთან დაკავშირებით ქვემოთ მოცემული წინადადებებიდან რომელია სწორი?", options:["ჩრდილის ზომები დღის განმავლობაში არ იცვლება","ჩრდილი ყველაზე მოკლეა როცა მზე ხის თავზეა","ჩრდილი ყველაზე მოკლეა მზის ამოსვლისას","ჩრდილი ყველაზე გრძელია მზის ამოსვლისას და მოკლე ჩასვლისას","ჩრდილი ყველაზე გრძელია როცა მზე ხის თავზეა"], answer:1, explanation:"\n    <b>მზის მდებარეობა და ჩრდილის სიგრძე:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 370 120\" style=\"max-width:370px\">\n      <line x1=\"20\" y1=\"100\" x2=\"350\" y2=\"100\" stroke=\"#282d3e\" stroke-width=\"1\"/>\n      <line x1=\"100\" y1=\"100\" x2=\"100\" y2=\"40\" stroke=\"#4f8cff\" stroke-width=\"3\"/>\n      <circle cx=\"100\" cy=\"35\" r=\"8\" fill=\"#2dd4a0\"/>\n      <text x=\"100\" y=\"25\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"8\">ხე</text>\n      <circle cx=\"40\" cy=\"30\" r=\"12\" fill=\"#ff5c6c\" opacity=\"0.8\"/>\n      <text x=\"40\" y=\"15\" text-anchor=\"middle\" fill=\"#ff5c6c\" font-size=\"8\">ამოსვლა</text>\n      <line x1=\"40\" y1=\"30\" x2=\"100\" y2=\"40\" stroke=\"#ff5c6c\" stroke-width=\"0.5\" stroke-dasharray=\"3\"/>\n      <rect x=\"100\" y=\"100\" width=\"200\" height=\"5\" rx=\"2\" fill=\"#ff5c6c\" opacity=\"0.3\"/>\n      <text x=\"200\" y=\"115\" text-anchor=\"middle\" fill=\"#ff5c6c\" font-size=\"8\">გრძელი ჩრდილი</text>\n      <circle cx=\"120\" cy=\"10\" r=\"12\" fill=\"#2dd4a0\"/>\n      <text x=\"140\" y=\"10\" fill=\"#2dd4a0\" font-size=\"8\">შუადღე (ზენიტი)</text>\n      <line x1=\"120\" y1=\"10\" x2=\"100\" y2=\"40\" stroke=\"#2dd4a0\" stroke-width=\"0.5\" stroke-dasharray=\"3\"/>\n      <rect x=\"100\" y=\"100\" width=\"15\" height=\"5\" rx=\"2\" fill=\"#2dd4a0\" opacity=\"0.5\"/>\n      <text x=\"115\" y=\"110\" fill=\"#2dd4a0\" font-size=\"7\">მოკლე</text>\n    </svg>\n    <br>\n    <b>მზის ამოსვლისას/ჩასვლისას</b>: სხივები ძალიან დახრილია → ჩრდილი ყველაზე <b>გრძელია</b>.\n    <br><b>შუადღისას (მზე ზენიტშია)</b>: სხივები თითქმის ვერტიკალურია → ჩრდილი ყველაზე <b>მოკლეა</b>.\n    <br><br>ჩრდილის სიგრძე მთელი დღის განმავლობაში იცვლება — დილით გრძელია, შუადღისას მოკლე, საღამოს ისევ გრძელი.\n  " },

  { id:23, text:"ჩამოთვლილი რიცხვებიდან რისი ტოლი შეიძლება იყოს გასაყოფის, გამყოფისა და განაყოფის ნამრავლი, თუ ყოველი მათგანი ნატურალური რიცხვია?", options:["13","18","48","36","56"], answer:3, explanation:"\n    <b>ალგებრული მსჯელობა:</b>\n    <br><br>\n    თუ <b>a ÷ b = c</b> (სადაც a, b, c ნატურალური რიცხვებია), მაშინ <b>a = b × c</b>.\n    <br><br>\n    ნამრავლი = a × b × c = (b×c) × b × c = <b>b² × c²</b> = <b>(b×c)²</b> = <b>a²</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 360 70\" style=\"max-width:360px\">\n      <rect x=\"5\" y=\"5\" width=\"350\" height=\"25\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"180\" y=\"22\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"11\">ნამრავლი ყოველთვის = a² (სრული კვადრატი)</text>\n      <rect x=\"5\" y=\"38\" width=\"350\" height=\"28\" rx=\"6\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1\"/>\n      <text x=\"180\" y=\"56\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"11\">36 = 6² ✓ | 6÷2=3 → 6×2×3=36 | 6÷3=2 → 6×3×2=36</text>\n    </svg>\n    <br>\n    <b>ვამოწმებთ:</b> 13 = არა კვადრატი ✗ | 18 = არა ✗ | 48 = არა ✗ | <b>36 = 6²</b> ✓ | 56 = არა ✗\n    <br><br>36÷6=6 → 36×6×6 = 1296; ან 36÷2=18 → 36×2×18 = 1296; ან 36÷3=12 → 36×3×12 = 1296. ყველა შემთხვევაში ნამრავლი = 36² = 1296.\n  " },

  { id:24, text:"რამდენჯერ გაიზრდება ორნიშნა რიცხვი, თუ მას მარჯვნიდან იმავე რიცხვს მივუწერთ?", options:["101-ჯერ","2-ჯერ","1001-ჯერ","12-ჯერ","100-ჯერ"], answer:0, explanation:"\n    <b>კონკრეტული მაგალითით:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 360 80\" style=\"max-width:360px\">\n      <rect x=\"5\" y=\"5\" width=\"130\" height=\"35\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1.5\"/>\n      <text x=\"70\" y=\"27\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"14\" font-weight=\"bold\">25</text>\n      <text x=\"143\" y=\"27\" fill=\"#e4e7ef\" font-size=\"16\">→</text>\n      <rect x=\"160\" y=\"5\" width=\"130\" height=\"35\" rx=\"6\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1.5\"/>\n      <text x=\"225\" y=\"27\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"14\" font-weight=\"bold\">2525</text>\n      <rect x=\"5\" y=\"48\" width=\"350\" height=\"28\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"180\" y=\"66\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"11\">2525 ÷ 25 = 101 → რიცხვი 101-ჯერ გაიზარდა</text>\n    </svg>\n    <br>\n    <b>ზოგადი ფორმულა:</b> N → N-ს მარჯვნიდან მივუწერთ N-ს. ორნიშნა N-ისთვის: ახალი რიცხვი = N×100 + N = <b>101×N</b>.\n    <br><br>\n    <b>კიდევ ერთი მაგალითი:</b> 73 → 7373 = 73 × 101. შემოწმებთ ნებისმიერი ორნიშნა რიცხვით — ყოველთვის <b>101-ჯერ</b> გაიზრდება.\n  " },

  { id:25, text:"ერთ მწკრივად დარგეს 25 ხე, ერთმანეთისაგან თანაბარი დაშორებით. შედეგად, მწკრივის სიგრძე 120 მეტრი გამოვიდა. რა მანძილია მეზობელ ხეებს შორის?", options:["4.8 მ","8 მ","4 მ","15 მ","5 მ"], answer:4, explanation:"\n    <b>„ღობის ბოძების\" კლასიკური ამოცანა:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 370 80\" style=\"max-width:370px\">\n      <line x1=\"20\" y1=\"40\" x2=\"350\" y2=\"40\" stroke=\"#282d3e\" stroke-width=\"1\"/>\n      <circle cx=\"20\" cy=\"30\" r=\"5\" fill=\"#2dd4a0\"/><text x=\"20\" y=\"22\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"7\">1</text>\n      <circle cx=\"57\" cy=\"30\" r=\"5\" fill=\"#2dd4a0\"/><text x=\"57\" y=\"22\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"7\">2</text>\n      <circle cx=\"94\" cy=\"30\" r=\"5\" fill=\"#2dd4a0\"/><text x=\"94\" y=\"22\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"7\">3</text>\n      <circle cx=\"131\" cy=\"30\" r=\"5\" fill=\"#2dd4a0\"/>\n      <text x=\"155\" y=\"35\" fill=\"#7a7f95\" font-size=\"10\">. . .</text>\n      <circle cx=\"313\" cy=\"30\" r=\"5\" fill=\"#2dd4a0\"/><text x=\"313\" y=\"22\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"7\">24</text>\n      <circle cx=\"350\" cy=\"30\" r=\"5\" fill=\"#2dd4a0\"/><text x=\"350\" y=\"22\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"7\">25</text>\n      <line x1=\"20\" y1=\"50\" x2=\"57\" y2=\"50\" stroke=\"#4f8cff\" stroke-width=\"1.5\"/>\n      <text x=\"38\" y=\"62\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"8\">d</text>\n      <text x=\"20\" y=\"70\" fill=\"#ff5c6c\" font-size=\"9\">|← 24 შუალედი →|</text>\n      <text x=\"240\" y=\"62\" fill=\"#7a7f95\" font-size=\"9\">120 მ</text>\n    </svg>\n    <br>\n    <b>მთავარი წესი:</b> N ხეს შორის არის <b>(N−1)</b> შუალედი, არა N!\n    <br><br>25 ხე → <b>24 შუალედი</b>. 120 ÷ 24 = <b>5 მეტრი</b>.\n    <br><br><b>ხშირი შეცდომა:</b> 120÷25 = 4.8 (არასწორი, რადგან ბოლო ხის შემდეგ შუალედი აღარ არის).\n  " },

  { id:26, text:"გვაქვს ბერკეტიანი სასწორი, დიდი რაოდენობის ბრინჯი და ორი საწონი გირა, მასებით 1 კგ და 3 კგ. რა მასის ბრინჯის აწონვაა შესაძლებელი კილოგრამების სიზუსტით, თუ აწონვის რაოდენობაში შეზღუდული არ ვართ?", options:["მხოლოდ 1 ან 3 კგ","მხოლოდ 1, 3 და 4 კგ","მხოლოდ 1, 2, 3 და 4 კგ","1-დან 10 კგ-მდე ნებისმიერი","ნებისმიერი მასის, ვიდრე ბრინჯი არ გამოილევა"], answer:4, explanation:"\n    <b>იტერაციული აწონვის მეთოდი:</b>\n    <br><br>\n    საკვანძო იდეა: <b>უკვე აწონილი ბრინჯი თავად ხდება საწონი!</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 370 130\" style=\"max-width:370px\">\n      <rect x=\"5\" y=\"5\" width=\"360\" height=\"22\" rx=\"4\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"15\" y=\"20\" fill=\"#4f8cff\" font-size=\"10\">ნაბიჯი 1: 1კგ გირით აწონე → 1კგ ბრინჯი</text>\n      <rect x=\"5\" y=\"30\" width=\"360\" height=\"22\" rx=\"4\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"15\" y=\"45\" fill=\"#4f8cff\" font-size=\"10\">ნაბიჯი 2: 1კგ ბრინჯი+გირი = 2კგ საწონი → 2კგ ბრინჯი</text>\n      <rect x=\"5\" y=\"55\" width=\"360\" height=\"22\" rx=\"4\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"15\" y=\"70\" fill=\"#4f8cff\" font-size=\"10\">ნაბიჯი 3: 3კგ გირით → 3კგ; ან 1+3=4კგ → 4კგ...</text>\n      <rect x=\"5\" y=\"80\" width=\"360\" height=\"22\" rx=\"4\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"15\" y=\"95\" fill=\"#4f8cff\" font-size=\"10\">ნაბიჯი 4: აწონილ ბრინჯს + გირებს ერთად იყენებ...</text>\n      <rect x=\"5\" y=\"105\" width=\"360\" height=\"22\" rx=\"4\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1.5\"/>\n      <text x=\"15\" y=\"120\" fill=\"#2dd4a0\" font-size=\"10\" font-weight=\"bold\">→ ნებისმიერი მთელი კილოგრამი, ვიდრე ბრინჯი არ ამოიწურება!</text>\n    </svg>\n    <br>\n    პროცესი უსასრულოდ გრძელდება: 1→2→3→4→5→... ყოველ ნაბიჯზე უკვე აწონილი ბრინჯი გირის როლს ასრულებს. შეზღუდვა მხოლოდ ბრინჯის რაოდენობაა.\n  " },

  { id:27, text:"ორი ავტომობილი მოძრაობს წრფივ გზატკეცილზე ერთი მიმართულებით, ერთმანეთის ტოლი 25 მ/წმ სიჩქარით. ავტომობილებს შორის 100 მეტრია. გზატკეცილის ბოლოს იწყება დაზიანებული გზა, რომელზეც თითოეული ავტომობილი გადასვლის შემდეგ სიჩქარეს 15 მ/წმ-მდე ამცირებს. რისი ტოლი გახდება ავტომობილებს შორის მანძილი, როდესაც ორივე ავტომობილი დაზიანებულ მონაკვეთზე?", options:["100 მეტრი","50 მეტრი","60 მეტრი","80 მეტრი","10 მეტრი"], answer:2, explanation:"\n    <b>ფაზებად ანალიზი:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 370 100\" style=\"max-width:370px\">\n      <rect x=\"200\" y=\"5\" width=\"165\" height=\"20\" rx=\"3\" fill=\"#2a1a1a\" stroke=\"#ff5c6c\" stroke-width=\"1\"/>\n      <text x=\"282\" y=\"18\" text-anchor=\"middle\" fill=\"#ff5c6c\" font-size=\"9\">დაზიანებული გზა (15მ/წმ)</text>\n      <rect x=\"5\" y=\"5\" width=\"195\" height=\"20\" rx=\"3\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1\"/>\n      <text x=\"102\" y=\"18\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"9\">ნორმალური გზა (25მ/წმ)</text>\n      <circle cx=\"200\" cy=\"42\" r=\"7\" fill=\"#4f8cff\"/>\n      <text x=\"200\" y=\"58\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"9\">A (წინ)</text>\n      <circle cx=\"100\" cy=\"42\" r=\"7\" fill=\"#a78bfa\"/>\n      <text x=\"100\" y=\"58\" text-anchor=\"middle\" fill=\"#a78bfa\" font-size=\"9\">B (უკან)</text>\n      <line x1=\"107\" y1=\"42\" x2=\"193\" y2=\"42\" stroke=\"#7a7f95\" stroke-width=\"1\" stroke-dasharray=\"3\"/>\n      <text x=\"150\" y=\"40\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"8\">100მ</text>\n      <rect x=\"5\" y=\"68\" width=\"360\" height=\"28\" rx=\"6\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1\"/>\n      <text x=\"180\" y=\"80\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"10\">A შედის დაზიანებულ გზაზე, ანელებს 15-მდე.</text>\n      <text x=\"180\" y=\"92\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"10\">B ჯერ 25-ით მოძრაობს → ახლოვდება A-ს!</text>\n    </svg>\n    <br>\n    <b>რა ხდება?</b> A (წინა) პირველი შედის დაზიანებულ მონაკვეთზე და ანელებს 15მ/წმ-მდე. B (უკანა) ჯერ კიდევ 25მ/წმ-ით მოძრაობს.\n    <br><br>\n    B-ს A-სთან მისვლამდე დრო: t = 100 ÷ 25 = <b>4 წამი</b>.\n    <br>4 წამში A (15მ/წმ-ით) გაივლის: 15 × 4 = <b>60 მ</b>.\n    <br>B მიაღწევს ზუსტად იმ წერტილს, სადაც A იყო → ახლა ისიც ანელებს.\n    <br><br>ახალი მანძილი = <b>60 მეტრი</b>. ამის შემდეგ ორივე 15მ/წმ-ით მოძრაობს → მანძილი აღარ იცვლება.\n  " },

  { id:28, text:"ღამურა მიფრინავს კედლისკენ, მის მარგობულად და უშვებს ბგერას, რომელიც კედლიდან ირეკლება და უბრუნდება მას, გაშვებიდან 2 წამში. ბგერის მიღების მომენტში ღამურა კედლიდან 300 მ-ითაა დაშორებული. რა მანძილზე იყო ღამურა კედლიდან დაშორებული ბგერის გაშვების მომენტში? ბგერის გავრცელების სიჩქარე ჰაერში 340 მ/წმ - ია.", options:["480 მ","380 მ","680 მ","340 მ","170 მ"], answer:1, explanation:"\n    <b>ექოლოკაციის ამოცანა:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 370 98\" style=\"max-width:370px\">\n      <rect x=\"340\" y=\"10\" width=\"10\" height=\"60\" rx=\"2\" fill=\"#7a7f95\"/>\n      <text x=\"355\" y=\"45\" fill=\"#7a7f95\" font-size=\"9\">კედელი</text>\n      <circle cx=\"50\" cy=\"40\" r=\"8\" fill=\"#4f8cff\"/>\n      <text x=\"50\" y=\"65\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"9\">გაშვება (d=?)</text>\n      <circle cx=\"150\" cy=\"40\" r=\"8\" fill=\"#2dd4a0\"/>\n      <text x=\"150\" y=\"65\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"9\">მიღება (300მ)</text>\n      <line x1=\"58\" y1=\"35\" x2=\"335\" y2=\"20\" stroke=\"#ff5c6c\" stroke-width=\"1\" stroke-dasharray=\"3\"/>\n      <text x=\"200\" y=\"18\" fill=\"#ff5c6c\" font-size=\"8\">ბგერა → კედელი (d)</text>\n      <line x1=\"335\" y1=\"30\" x2=\"158\" y2=\"40\" stroke=\"#a78bfa\" stroke-width=\"1\" stroke-dasharray=\"3\"/>\n      <text x=\"250\" y=\"48\" fill=\"#a78bfa\" font-size=\"8\">ბგერა ← ღამურა (300მ)</text>\n      <rect x=\"5\" y=\"72\" width=\"360\" height=\"18\" rx=\"4\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1\"/>\n      <text x=\"180\" y=\"84\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"10\" font-weight=\"bold\">ბგერის გზა = d + 300 = 340×2 = 680 → d = 380მ</text>\n    </svg>\n    <br>\n    <b>ბგერის ჯამური გზა</b> = კედლამდე (d) + უკან ღამურამდე (300მ). 2 წამში ბგერა გაივლის 340×2 = <b>680 მ</b>.\n    <br>d + 300 = 680 → d = <b>380 მ</b>.\n    <br><br><b>შენიშვნა:</b> ღამურა ამ დროს კედლისკენ მიფრინავს, ამიტომ ბრუნების მანძილი (300) ნაკლებია საწყისზე (380).\n  " },

  { id:29, text:"მხოლოდ 5 ლიტრიანი და 3 ლიტრიანი ჭურჭლებით, რომლებსაც დანაყოფები არ აქვთ, როგორ ავავსოთ ონკანიდან ზუსტად 1 ლიტრი წყალი?", options:["ავავსოთ 3ლ, გადავასხათ 5ლ-ში, კიდევ 3ლ გადავასხათ. 3ლ-ში დარჩება 1ლ","ავავსოთ 5ლ, გადავასხათ 3ლ-ში. 5ლ-ში დარჩება 1ლ","ავავსოთ 3ლ, გადავასხათ 5ლ-ში. 5ლ-ში მივიღებთ 1ლ","ავავსოთ 5ლ, გადავღვაროთ 4ლ","შეუძლებელია"], answer:0, explanation:"\n    <b>კლასიკური „ჭურჭლების\" ამოცანა — ნაბიჯ-ნაბიჯ:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 370 145\" style=\"max-width:370px\">\n      <rect x=\"5\" y=\"5\" width=\"360\" height=\"30\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"15\" y=\"24\" fill=\"#4f8cff\" font-size=\"10\" font-weight=\"bold\">ნაბიჯი 1:</text>\n      <text x=\"95\" y=\"24\" fill=\"#e4e7ef\" font-size=\"10\">ავავსებთ 3ლ-ს ონკანიდან</text>\n      <text x=\"290\" y=\"24\" fill=\"#7a7f95\" font-size=\"10\">[3ლ: 3] [5ლ: 0]</text>\n      <rect x=\"5\" y=\"40\" width=\"360\" height=\"30\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"15\" y=\"59\" fill=\"#4f8cff\" font-size=\"10\" font-weight=\"bold\">ნაბიჯი 2:</text>\n      <text x=\"95\" y=\"59\" fill=\"#e4e7ef\" font-size=\"10\">3ლ-დან ვასხამთ 5ლ-ში</text>\n      <text x=\"290\" y=\"59\" fill=\"#7a7f95\" font-size=\"10\">[3ლ: 0] [5ლ: 3]</text>\n      <rect x=\"5\" y=\"75\" width=\"360\" height=\"30\" rx=\"6\" fill=\"#1a2744\" stroke=\"#4f8cff\" stroke-width=\"1\"/>\n      <text x=\"15\" y=\"94\" fill=\"#4f8cff\" font-size=\"10\" font-weight=\"bold\">ნაბიჯი 3:</text>\n      <text x=\"95\" y=\"94\" fill=\"#e4e7ef\" font-size=\"10\">კიდევ ავავსებთ 3ლ-ს</text>\n      <text x=\"290\" y=\"94\" fill=\"#7a7f95\" font-size=\"10\">[3ლ: 3] [5ლ: 3]</text>\n      <rect x=\"5\" y=\"110\" width=\"360\" height=\"30\" rx=\"6\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"2\"/>\n      <text x=\"15\" y=\"129\" fill=\"#2dd4a0\" font-size=\"10\" font-weight=\"bold\">ნაბიჯი 4:</text>\n      <text x=\"95\" y=\"129\" fill=\"#e4e7ef\" font-size=\"10\">3ლ-დან ვასხამთ 5ლ-ში (2ლ ეტევა)</text>\n      <text x=\"290\" y=\"129\" fill=\"#2dd4a0\" font-size=\"10\" font-weight=\"bold\">[3ლ: 1] [5ლ: 5]</text>\n    </svg>\n    <br>\n    5ლ-იან ჭურჭელში უკვე 3 ლიტრი იყო, ამიტომ მხოლოდ <b>2 ლიტრი</b> ეტევა. 3-ლიტრიანიდან 2 გადავა, დარჩება <b>1 ლიტრი</b>.\n    <br><br>\n    <b>რატომ არასწორია ბ)?</b> 5−3=2, არა 1. <b>რატომ გ)?</b> 3ლ 5ლ-ში გადასხმისას 3ლ მიიღება, არა 1. <b>რატომ დ)?</b> „4 ლიტრის გადაღვრა\" ზუსტად ვერ გაზომავ დანაყოფების გარეშე.\n  " },

  { id:30, text:"ორი მონადირე, რომელთა შორის მანძილი 200 მ - ია, მირბიან ერთმანეთისკენ თითოეული 5 მ/წმ სიჩქარით. ამ მომენტიდან ერთ-ერთი მონადირის ძაღლი გაიქცა მეორე მონადირესთან, შემდეგ კვლავ მირბინა პირველთან, შემდეგ კვლავ მეორესთან და ასე დარბოდა, ვიდრე მონადირეები ერთმანეთს შეხვდნენ. რა მანძილი გაიარა ძაღლმა თუ იგი 8 მ/წმ სიჩქარით დარბოდა?", options:["600 მ","300 მ","160 მ","200 მ","450 მ"], answer:2, explanation:"\n    <b>ელეგანტური ამოხსნა — ძაღლის გზის ნაცვლად ვიპოვოთ დრო:</b>\n    <br><br>\n    <svg width=\"100%\" viewBox=\"0 0 370 98\" style=\"max-width:370px\">\n      <circle cx=\"30\" cy=\"35\" r=\"10\" fill=\"#4f8cff\"/>\n      <text x=\"30\" y=\"58\" text-anchor=\"middle\" fill=\"#4f8cff\" font-size=\"9\">მონადირე 1</text>\n      <text x=\"30\" y=\"70\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"8\">5 მ/წმ →</text>\n      <circle cx=\"340\" cy=\"35\" r=\"10\" fill=\"#ff5c6c\"/>\n      <text x=\"340\" y=\"58\" text-anchor=\"middle\" fill=\"#ff5c6c\" font-size=\"9\">მონადირე 2</text>\n      <text x=\"340\" y=\"70\" text-anchor=\"middle\" fill=\"#7a7f95\" font-size=\"8\">← 5 მ/წმ</text>\n      <line x1=\"40\" y1=\"35\" x2=\"330\" y2=\"35\" stroke=\"#282d3e\" stroke-width=\"1.5\" stroke-dasharray=\"5\"/>\n      <text x=\"185\" y=\"30\" text-anchor=\"middle\" fill=\"#e4e7ef\" font-size=\"10\">200 მ</text>\n      <text x=\"185\" y=\"15\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"9\">🐕 8 მ/წმ (მათ შორის დარბის)</text>\n      <rect x=\"5\" y=\"76\" width=\"360\" height=\"16\" rx=\"4\" fill=\"#1e3a2a\" stroke=\"#2dd4a0\" stroke-width=\"1\"/>\n      <text x=\"180\" y=\"88\" text-anchor=\"middle\" fill=\"#2dd4a0\" font-size=\"10\" font-weight=\"bold\">მიახლოება: 5+5=10მ/წმ → t = 200/10 = 20წმ → ძაღლი: 8×20 = 160მ</text>\n    </svg>\n    <br>\n    <b>არ არის საჭირო ძაღლის რთული ტრაექტორიის გამოთვლა!</b>\n    <br><br>\n    მონადირეები ერთმანეთისკენ მირბიან — მიახლოების სიჩქარე = 5+5 = <b>10 მ/წმ</b>.\n    <br>შეხვედრის დრო = 200 ÷ 10 = <b>20 წამი</b>.\n    <br>ძაღლი ამ 20 წამის განმავლობაში უწყვეტად რბოდა 8 მ/წმ-ით.\n    <br>გზა = 8 × 20 = <b>160 მ</b>.\n    <br><br>\n    <b>ხრიკი:</b> არ აქვს მნიშვნელობა ძაღლი რამდენჯერ შეტრიალდა — მთავარია საერთო დრო და მისი სიჩქარე.\n  " },
]
});
